window.__QUIZ_DATA__=[{"id":"objective>Mathematics>2014>1","subject":"Mathematics","year":"2014","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Simplify:1025-623+3","images":[],"options":{"A":"6415","B":"61115","C":"7415","D":"71115"},"answer":"B","explanation":"102/5 - 62/3 + 3      52/5 - 20/3 + 3/1      156 - 100 + 4515     101/15      = 611/15","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>2","subject":"Mathematics","year":"2014","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBER BASES","question":"If 23x = 325. Find the value of x.","images":[],"options":{"A":"7","B":"6","C":"5","D":"4"},"answer":"A","explanation":"Given:  23x = 325;   convert both sides to base 10  2X + 3 = 15 + 2;   2X + 3 = 17;   2X = 17 - 3   2X = 14 ;   X = 14/2    X = 7","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2014>3","subject":"Mathematics","year":"2014","type":"Objective","topic":"MENSURATION : VOLUMES","question":"The volume of a cube is 512cm3. Find the length of its side.","images":[],"options":{"A":"6cm","B":"7cm","C":"8cm","D":"9cm"},"answer":"C","explanation":"Given:  Volume of a cube = 512 cm3  Length of its side = l  Recall: Volume of cube, V = l3  \u2234 512 = l3  &#179&radic;512&nbsp; = l   l = 8cm.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>4","subject":"Mathematics","year":"2014","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The bar chart below shows the scores of some scores of some students in a test. Use it to answer this question     How many students took the test?","images":["data:image/png;base64,"],"options":{"A":"18","B":"19","C":"20","D":"22"},"answer":"C","explanation":"Score 0 = 4 students  Score 1 = 2 students   Score 2 = 5 students   Score 3 = 6 students    Score 4 = 3 students   Total = 20 students","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2014>5","subject":"Mathematics","year":"2014","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"The bar chart below shows the scores of some scores of some students in a test. Use it to answer this question   If one student is selected at random, find the probability that he/she scored at most 2 marks","images":["data:image/png;base64,"],"options":{"A":"11/18","B":"11/20","C":"7/22","D":"5/19"},"answer":"B","explanation":"At most 2 marks = 5 + 2 + 4 students = 11 students    Probability (at most 2 marks) = 11/20","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>6","subject":"Mathematics","year":"2014","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Simplify: &radic;12&nbsp;(&radic;48&nbsp; - &radic;3&nbsp;)","images":[],"options":{"A":"18","B":"16","C":"14","D":"12"},"answer":"A","explanation":"Given:  &radic;12&nbsp;(&radic;48&nbsp; - &radic;3&nbsp;)    &radic;4 x 3&nbsp;(&radic;16 x 3 &nbsp; - &radic;3&nbsp;)     2&radic;3&nbsp;(4&radic;3&nbsp; - &radic;3&nbsp;)   2&radic;3&nbsp; x &radic;2&nbsp;(4 - 1)    2&radic;9&nbsp;(3) = 6 x 3 = 18","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2014>7","subject":"Mathematics","year":"2014","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"Which of the following number lines represents the solution to the inequality: -9 \u2264 2/3x - 7","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"D","explanation":"-9 \u22642/3x - 7 2/3x - 7    multiply through by 3    -27 \u22642x - 21    collect like terms    27 + 21 \u2264 2x      6 \u2264 2x    divide both sides by 2    -6/2 \u2264 2x/2    = -3 \u2264 x     then,    2/3x - 7   multiply through by 3    2x - 21   collect like terms    2x   2x  x 36/2    x  \u2234 -3 \u2264 x","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>8","subject":"Mathematics","year":"2014","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, the value of x + y = 220o. Find the value of n.","images":["data:image/png;base64,"],"options":{"A":"20o","B":"40o","C":"60o","D":"80o"},"answer":"B","explanation":"Given:    x + y = 220\u00b0 ----- (i)    z + n = x ----- (ii) (ext. angle of a \u0394 equals sum of two opp. int. angles of the \u0394)    k + n = y ----- (iii) (ext. angle of a \u0394 equals sum of two opp. int. angles of the \u0394)    n + z + k = 180\u00b0 ----- (iv) (sum of angles in a \u0394 is 180\u00b0)    Substitute (ii) and (iii) in (i)    z + n + k + n = 220\u00b0    z + k + 2n = 220\u00b0 ----- (v)    From (iv)    z + k = 180\u00b0 - n ----- (vi)    Substitute (180\u00b0 - n) for (z + k) in (v)    180\u00b0 - n + 2n = 220\u00b0    180\u00b0 + n = 220\u00b0    n = 220\u00b0 - 180\u00b0    \u2234 n = 40\u00b0","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2014>9","subject":"Mathematics","year":"2014","type":"Objective","topic":"NUMBER AND NUMERATION : LOGICAL REASONING","question":"Given that x > y and 3  I. y > 3    II. x  III. x > y > 3","images":[],"options":{"A":"I only","B":"I and II only","C":"I and III only","D":"I, II and III"},"answer":"C","explanation":"x > y -------------- *  3  \u2234 y > 3   x > y > 3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>10","subject":"Mathematics","year":"2014","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR EQUATIONS IN ONE VARIABLE","question":"Three quarters of a number added to two and a half of that number gives 13. Find the number.","images":[],"options":{"A":"4","B":"5","C":"6","D":"7"},"answer":"A","explanation":"Let the number be x  34x+52x=13  N.B:212=52  3x4+10x4=13  3x+10x4=13  13x4=13  13x = 52  x = 4","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2014>11","subject":"Mathematics","year":"2014","type":"Objective","topic":"NUMBER AND NUMERATION : SETS","question":"If X = {0, 2, 4, 6), Y = {1, 2, 3,4} and Z = {1,3} are subsets of U = {x : 0 \u2264 x \u2264 6}, find x \u2229 (Y' \u222a Z).","images":[],"options":{"A":"{0, 2, 6}","B":"{1, 3}","C":"{0, 6}","D":"{}"},"answer":"C","explanation":"Parameters given:  X = {0,2,4,6};   Y = {1,2,3,4};   Z = {1,3}   U = {x : 0 \u2264 x \u2264 6}  U = {0, 1, 2, 3, 4, 5, 6}   X \u2229 (Y' \u222a Z) = ?  N.B: Y' = {0, 5, 6}  \u2234 Y' \u222a Z = {0, 1, 3, 5, 6}    then X \u2229 (Y' \u222a Z) = {0, 2, 4, 6} \u2229 {0, 1, 3, 5, 6} = {0, 6}","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>12","subject":"Mathematics","year":"2014","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"Find the truth set of the equation x2 = 3(2x + 9)","images":[],"options":{"A":"{x : x = 3, x = 9}","B":"{x : x = -3, x = -9}","C":"{x : x = 3, x = -9}","D":"{x : x = -3, x = 9}"},"answer":"D","explanation":"Given:  the equation \u2192 x2 = 3(2x + 9)  x2 = 6x + 27   x2 - 6x - 27 = 0;   x2 - 9x + 3x - 27 = 0  x(x - 9) + 3(x - 9) = (x + 3)(x - 9) = 0    x + 3 = 0 or x - 9 = 0    x = -3 or x = 9   {x: x = -3 , x = 9}","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2014>13","subject":"Mathematics","year":"2014","type":"Objective","topic":"COORDINATE GEOMETRY OF STRAIGHT LINES : CONCEPT OF THE X-Y PLANE AND COORDINATES OF POINTS ON THE X-Y PLANE","question":"The coordinates of points P and Q are (4, 3) and (2,1) respectively. Find the shortest distance between P and Q.","images":[],"options":{"A":"10&radic;2&nbsp;","B":"4&radic;5&nbsp;","C":"5&radic;2&nbsp;","D":"2&radic;5&nbsp;"},"answer":"D","explanation":"Parameters given  Coordinate of P = (4, 3)  Coordinate of Q = (2, -1)   We are asked to find the distance between two points.  Recall: If two points are given, say A and B  A(x1, y1) and B(x2, y2)     Distance = &radic;(x2 - X1)2 + (Y2 - Y1)2&nbsp;   d = &radic;(2 -4)2 + (-1-3)2&nbsp;   d = &radic;(-2)2 + (-4)2&nbsp;  d = &radic;4 + 16&nbsp; = &radic;20&nbsp; = &radic;4 x 5&nbsp; = 2&radic;5&nbsp;","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2014>14","subject":"Mathematics","year":"2014","type":"Objective","topic":"ALGEBRAIC PROCESSES : CHANGE OF SUBJECT OF A FORMULA/RELATION","question":"Makeuthesubjectoftheformula,E=m2g(v2 - u2)","images":[],"options":{"A":"U=&radic;(v2-2gEm)&nbsp;","B":"U=&radic;(v2m-2gE4)&nbsp;","C":"U=&radic;(v-2gEm)&nbsp;","D":"U=&radic;(2V2gEm)&nbsp;"},"answer":"A","explanation":"Given:  E=m2g(v2-u2)  2gE = m(v2 - u2)  \u2234 mv2 - mu2 = 2gE  mv2 - 2gE = mu2  \u2234mv2-2gEm=u2  v2-2gEm=u2  u=&radic;v2-2gEm&nbsp;","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2014>15","subject":"Mathematics","year":"2014","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram above, \u2220QPT = \u2220PTS = 90o   \u2220PQR = 110o and \u2220TSR = 20o.    Find the size of the obtuse angle QRS","images":["data:image/png;base64,"],"options":{"A":"140o","B":"130o","C":"120o","D":"110o"},"answer":"B","explanation":"Given the diagram below     N.B: PQRST is a pentagon  Recall: The sum of the interior angles of a pentagon = 540\u00b0  \u2234 540 = 90 + 90 + 110 + 20 +  540 = 290 + 20 +  540 = 310 +   N.B: QRS (obtuse) + QRS (reflex) = 360\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>16","subject":"Mathematics","year":"2014","type":"Objective","topic":"NUMBER AND NUMERATION : VARIATION","question":"If x varies inversely as y and y varies directly as z, what is the relationship between x and z?","images":[],"options":{"A":"x \u221d Z","B":"x\u221d1z","C":"x \u221d z2","D":"x\u221d1z2"},"answer":"B","explanation":"Given:  x\u03b11y------------------(1)  y \u03b1 z --------------------- (2)  x = k/y  ---(3)  k = xy  y = kz -----(4)  k = y/z  xy = y/z  x = 1/2  x\u03b11z","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2014>17","subject":"Mathematics","year":"2014","type":"Objective","topic":"COORDINATE GEOMETRY OF STRAIGHT LINES : CONCEPT OF THE X-Y PLANE AND COORDINATES OF POINTS ON THE X-Y PLANE","question":"Find the gradient of the line joining the points (2, -3) and (2, 5).","images":[],"options":{"A":"0","B":"1","C":"2","D":"undefined"},"answer":"D","explanation":"Parameters given:  Two points, A(2, -3) and B(2, 5)  Recall: If two points A (x, y) and B(x2, y2) are given then the gradient is given as   m=y2 - y1x2 - x1  \u2234m=5-(-3)2-2=80=undefined","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>18","subject":"Mathematics","year":"2014","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"If (x - a) is a factor of bx - ax + x2 - ab, find the other factor.","images":[],"options":{"A":"(x + b)","B":"(x - b)","C":"(a + b)","D":"(a - b)"},"answer":"A","explanation":"Given:  (x - a) = = \u2192 a factor  bx - ax + x2 - ab = = \u2192 the polynomial   To get the other factor, we will factorize simply   bx + x2 - ax - ab  x(b + x) - a(b + x)  (x - a)(b + x)  The other factor is (b + x)","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2014>19","subject":"Mathematics","year":"2014","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"Height23456Frequency24531   The table shows the distribution of the height of plants in a nursery. Calculate the mean height of the plants.","images":[],"options":{"A":"3.8","B":"3.0","C":"2.8","D":"2.3"},"answer":"A","explanation":"height (x) frequency (f) fx2  3  4  5  62  4  5  3  14  12  20   15  6    mean=\u2211fx\u2211f=(2 x 2)+(3 x 4)+(4 x 5)+(5 x 3)+(6 x 1)2+4+5+3+1=16+20+2115=5715=3.8","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>20","subject":"Mathematics","year":"2014","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, PQR is a straight line, (m + n) = 120o and (n + r) = 100o. Find (m + r).","images":["data:image/png;base64,"],"options":{"A":"110o","B":"120o","C":"140o","D":"160o"},"answer":"C","explanation":"Given the diagram below:    m + n = 120\u00b0 ---------------- (1)  n + r = 100\u00b0 ------------------- (2)  N.B: m + n + r = 180\u00b0 (sum of angles on a straight line)  (m + n) + r = 180\u00b0  120 + r = 180\u00b0  r = 60o    From (2)  n + r = 100o   n = 100\u00b0 - 60   n = 40\u00b0   m = 180o - 100o = 80\u00b0    \u2234 m + r = 80o + 60\u00b0 = 140\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>21","subject":"Mathematics","year":"2014","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"In the diagram, SR is parallel to UW    \u2220WVT = xo, \u2220VUT = yo    \u2220RSV = 45o and \u2220VTU = 20o    Use the diagram to answer this question  Find the value of x.","images":["data:image/png;base64,"],"options":{"A":"20\u00b0","B":"45\u00b0","C":"65\u00b0","D":"135\u00b0"},"answer":"B","explanation":"Given: the diagram below    N.B: SR//UW (SR is parallel to VW)  Since : SR is parallel to VW, then:  \u2220TVW = x = 45\u00b0 (corresponding angles)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>22","subject":"Mathematics","year":"2014","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"In the diagram, SR is parallel to UW    \u2220WVT = xo, \u2220VUT = yo    \u2220RSV = 45o and \u2220VTU = 20o    Use the diagram to answer this question    Calculate the value of y.","images":["data:image/png;base64,"],"options":{"A":"20","B":"25","C":"45","D":"65"},"answer":"B","explanation":"In \u0394VUT    45\u00b0 = y + 20\u00b0 (exterior angles of a triangle)  y = 25\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>23","subject":"Mathematics","year":"2014","type":"Objective","topic":"MENSURATION : AREAS","question":"The area of a sector a circle with diameter 12cm is 66cm2. If the sector is folded to form a cone. Calculate the radius of the base of the cone. [Take \u03c0 = 22/7]","images":[],"options":{"A":"3.0cm","B":"3.5cm","C":"7.0cm","D":"7.5cm"},"answer":"B","explanation":"Parameters given:  diameter, d = 12cm     radius=122cm=6cm   area of sector, A = 66cm2   Radius of cone, r = ?  N.B: Length of the arc of the sector = Circumference of the base of the cone;  Recall:Lengthofarc=2\u00d7Ar  L=2\u00d7666=22cm  22=2\u00d7227\u00d7r  r=72=3.5cm","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2014>24","subject":"Mathematics","year":"2014","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"A chord, 7cm long, is drawn in a circle with radius 3.7cm. Calculate the distance of the chord from the centre of the circle.","images":[],"options":{"A":"0.7cm","B":"1.2cm","C":"2.0cm","D":"2.5cm"},"answer":"B","explanation":"Parameters given:  Length of chord, L = 7cm  Radius, r = 3.7cm  Distance of chord from the centre, x = ?  Diagrammatically, we have       From Pythagoras theorem  (3.7)2 = (3.5)2 + x2  13.69 = 12.25 + x2  1.44 = x2  x = 1.2cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>25","subject":"Mathematics","year":"2014","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"Which of the following is a measure of dispersion?","images":[],"options":{"A":"Range","B":"Percentile","C":"Median","D":"Quartile"},"answer":"A","explanation":"While percentiles, median, and quartiles provide information about the distribution of data, the range specifically measures the spread or dispersion of values within a dataset.","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2014>26","subject":"Mathematics","year":"2014","type":"Objective","topic":"ALGEBRAIC PROCESSES : SIMULTANEOUS LINEAR EQUATIONS IN TWO VARIABLES","question":"A box contains 13 currency notes, all of which are either \u20a650 or \u20a620 notes. The total value of the currency notes is \u20a6530. How many \u20a650 notes are in the box?","images":[],"options":{"A":"4","B":"6","C":"8","D":"9"},"answer":"D","explanation":"Parameters given:  Total number of notes = 13  Let x be the total number of \u20a650 notes and y be the total number of \u20a620 notes.  x + y = 13 ------------ (1)  50x + 20y = 530 ---------------- (2)  From (1) x = 13 - y ---------------- (3)  substitute for x = 13 - y in (2)  50(13 - y) + 20y = 530  650 - 50y + 20y = 530  650 - 30y = 530  -30y = 530 - 650  -30y = -120  y = 4  From (1)  x + 4 = 13  x = 9  There are nine (9), \u20a650 notes","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>27","subject":"Mathematics","year":"2014","type":"Objective","topic":"ALGEBRAIC PROCESSES : GRAPHS OF LINEAR AND QUADRATIC FUNCTIONS","question":"The graph below is for the relation y = 2x2 + x - 1.   Use it to answer this question     What are the coordinates of the point S?","images":["data:image/png;base64,"],"options":{"A":"(1,0.2)","B":"(1, 0.4)","C":"(1, 2.0)","D":"(1, 4.0)"},"answer":"C","explanation":"The  coordinates  of  the point  S  is (1 ,  2.0).","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>28","subject":"Mathematics","year":"2014","type":"Objective","topic":"ALGEBRAIC PROCESSES : GRAPHS OF LINEAR AND QUADRATIC FUNCTIONS","question":"The graph below is for the relation y = 2x2 + x - 1.   Use it to answer this question   Find the minimum value of y.","images":["data:image/png;base64,"],"options":{"A":"0.00","B":"-0.65","C":"-1.25","D":"-2.10"},"answer":"C","explanation":"The  minimum  value  of  y is at the point  -1.25.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>29","subject":"Mathematics","year":"2014","type":"Objective","topic":"TRIGONOMETRY : BEARINGS","question":"A ship sails x km due east to a point E and continues x km due north to F. Find the bearing of F from the starting point.","images":[],"options":{"A":"045o","B":"090o","C":"135o","D":"225o"},"answer":"A","explanation":"Given: the information in the question    N.B: \u03b8 = 45\u00b0  \u2234 the bearing of F from the starting point = 045o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>30","subject":"Mathematics","year":"2014","type":"Objective","topic":"NUMBER AND NUMERATION : RATIO, PROPORTIONS AND RATES","question":"If x : y = 3 : 2  and y : z = 5 : 4. Find the value of x in the ratio x : y : z.","images":[],"options":{"A":"8","B":"10","C":"15","D":"20"},"answer":"C","explanation":"Parameters given:   x/y = 3/2 -------------------- (1)   y/z = 5/4 -------------------- (2)  3y = 2x  x=3y2-------------(3)  From (2)  4y = 5z  z=4y5--------------------(4)  z=4(3y/2)5=6y5------------------(5)  x:y:z=3y2:y:4y5  multiply through by 10  x : y : z = 15y : 10y : 8y  x : y : z = 15 : 10 : 8","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2014>31","subject":"Mathematics","year":"2014","type":"Objective","topic":"NUMBER AND NUMERATION : PROFIT AND LOSS","question":"A trader bought sachet water for GHc55.00 per dozen and sold them at 10 for GHc50.00. Calculate correct to 2 decimal places, his percentage gain.","images":[],"options":{"A":"8.00%","B":"8.30%","C":"9.09%","D":"10.00%"},"answer":"C","explanation":"Parameters given:  Cost Price = GH\u2284 55.00 per dozen  Selling Price = 10 for GH\u2284 50.00  % gain = ?  10 satchets \u2261 GH\u228450.00  2 satchets \u2261 x  102=50x  10x = 100  x =  GH\u2284 10.00  The amount realised from the sale of the satchets  = 10 + 50 = GH\u2284 60.00  Recall:%gain=gaincost price\u00d71001  %gain=60 - 5555\u00d7100  %gain=555\u00d7100=10011\u22489.09%","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>32","subject":"Mathematics","year":"2014","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"In the figure, PQ is a tangent to the circle at R and UT is parallel to PQ. If \u2220TRQ = xo, Find \u2220URT in terms of x.","images":["data:image/png;base64,"],"options":{"A":"2xo","B":"(90 - x)o","C":"(90 + x)o","D":"(180 - 2x)o"},"answer":"D","explanation":"Given: the circle below     \u2220URT = ? ------------- (1)  \u2220TRQ = x  N.B: UT is parallel to RQ  x\u00b0 = \u2220RTU (alternate angles)  Also, x\u00b0 = \u2220TUR (angle in alternate segment)  \u2234 IN \u0394URT  \u2220TUR + \u2220URT + \u2220RTU = 180\u00b0 (sum of angles in a \u0394)  x + x + \u2220URT = 180\u00b0  2x + \u2220URT = 180\u00b0  \u2234 \u2220URT = 180 - 2x","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2014>33","subject":"Mathematics","year":"2014","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"Given that cos x = 12/13, evaluate1 - tanxtanx","images":[],"options":{"A":"5/13","B":"5/7","C":"7/5","D":"13/5"},"answer":"C","explanation":"Parameters given:  cosx=1213------------(1)  1-tanxtanx------------(2)  Recall:cos\u03b8=adjhyp  tan\u03b8=oppadj  Represent the information on a right-angled \u0394    Recall: Pythagora's Theorem  (13)2 = (12)2 + (opp)2  169 = 144 + (opp)2  25 = (opp)2  opp = &radic;25&nbsp; = 5  tanx=512  1-tanxtanx=1 - 5/125/12=7/125/12=75","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2014>34","subject":"Mathematics","year":"2014","type":"Objective","topic":"NUMBER AND NUMERATION : FRACTIONS, DECIMALS AND APPROXIMATIONS","question":"Approximate 0.0033780 to 3 significant figures.","images":[],"options":{"A":"338","B":"0.338","C":"0.00338","D":"0.003"},"answer":"C","explanation":"o approximate the number 0.0033780 to three significant figures, we focus on the first three non-zero digits. The non-zero digits in this number are 3, 3, and 7.    So, 0.0033780 rounded to three significant figures is:    0.00338.","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2014>35","subject":"Mathematics","year":"2014","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Simplify:&radic;(82 x 4n + 122n x 16)&nbsp;","images":[],"options":{"A":"16","B":"8","C":"4","D":"1"},"answer":"C","explanation":"&radic;(82 x 4n - 122n x 16)&nbsp;    =&radic;23(2) x 22(n + 1)22n x 21&nbsp;)  =&radic;(26 x 22n + 222n + 4)&nbsp;   = &radic;22n+8 \u00f7 22n + 4&nbsp;    = &radic;22n - 2n + 8 - 4&nbsp; = &radic;24&nbsp;   = &radic;16&nbsp; = 4","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2014>36","subject":"Mathematics","year":"2014","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"If2x - 3-3x - 2isequaltop(x-3)(x - 2)   Find P","images":[],"options":{"A":"-x - 5","B":"-(x + 3)","C":"5x - 13","D":"5 -x"},"answer":"D","explanation":"2x-3-3x-2=P(x - 3)(x - 2)  2(x-2)-3(x-3)(x -3)(x - 2)=P(x-3)(x-2)   =2x - 4 - 3x + 9(x-3)(x-2)=P(x-3)(x-2)   -x+5(x - 3)(x - 2)=P(x - 3)(x - 2)    P = -x + 5 or P = 5 - x","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>37","subject":"Mathematics","year":"2014","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Subtract12(a-b-c)fromthesumof12(a-b+c)and12(a+b-c)","images":[],"options":{"A":"12(a+b+c)","B":"12(a-b-c)","C":"12(a-b+c)","D":"13(a+b-c)"},"answer":"A","explanation":"1/2(a - b + c) + 1/2(a + b - c) - 1/2(a - b - c)     1/2a - 1/2b + 1/2c + 1/2a + 1/2b - 1/2c - 1/2a + 1/2b + 1/2c      = 1/2a + 1/2b + 1/2c      = 1/2(a + b + c)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>38","subject":"Mathematics","year":"2014","type":"Objective","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"A man's eye level is 1.7m above the horizontal ground and 13m from a vertical pole. If the pole is 8.3m high. Calculate, correct to the nearest degrees, the angle of elevation of the top pole from his eyes.","images":[],"options":{"A":"33o","B":"32o","C":"27o","D":"26o"},"answer":"C","explanation":"Parameters given:  the information given in the question    tan\u03b8=8.313  \u03b8=tan-1(8.313)=0.62  \u03b8 = tan-1(0.62)  \u03b8 = 27\u00b0","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2014>39","subject":"Mathematics","year":"2014","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"A chord subtends an angle of 120o at the centre of a circle of radius 3.5cm. Find the perimeter of the minor sector containing the chord. [Take \u03c0 = 22/7]","images":[],"options":{"A":"141/3cm","B":"125/6cm","C":"81/7cm","D":"71/3cm"},"answer":"A","explanation":"Parameters given:  Angle substended at the centre, \u03b8 = 120\u00b0  Radius, r = 3.5cm  Perimeter of minor sector, P = ?  Diagrammatically,    N.B: Perimeter of Sector, P = 2r + L --------------- (1)  Recall:L(lengthofarc)=\u03b8360\u00d72\u03c0r  P=2r+\u03b83602\u03c0r  P=2(3.5)+120360\u00d72\u00d7227\u00d73.5  P=7.0+446  P=7.0cm+223cm  P = 7.0cm + 7.3cm  P = 14.3cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>40","subject":"Mathematics","year":"2014","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In parallelogram PQRS, QR is produced to M such that |QR| = |RM|. What fraction of the area of PQMS is the area of PRMS?","images":[],"options":{"A":"14","B":"13","C":"23","D":"34"},"answer":"C","explanation":"Given: the information in the question    In PQMS, there are 3 triangles, i.e \u0394PQR, \u0394PRS and \u0394SRM.  In PRMS, there are 2 triangles, i.e \u0394PRS and \u0394SRM  \u2234TheareaofPRMS=23\u00d7theareaofPQMS","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>41","subject":"Mathematics","year":"2014","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"Determine the value of m in the diagram","images":["data:image/png;base64,"],"options":{"A":"80o","B":"90o","C":"110o","D":"150o"},"answer":"B","explanation":"Given: the diagram below    N.B: ABCD is a cyclic quadrilateral  \u2220D + \u2220B = 180\u00b0 (opposite angles of a cyclic quadrilateral)  \u2220D + 80 = 180\u00b0  \u2220D = 100\u00b0  Split the quadrilateral in into two at AC.    \u0394ADC is isosceles (two equal sides)  \u2234 100\u00b0 + x + x = 180\u00b0 (sum of the angles in a \u0394)  100 + 2x = 180  2x = 80  x = 40\u00b0  Also, \u0394ABC is isosceles (two equal sides)  80 + y + y = 180\u00b0 (sum of the angles in a \u0394)  80 + 2y = 180  2y = 100  y = 50\u00b0  N.B: x + y = m, m = 50 + 40 = 90\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>42","subject":"Mathematics","year":"2014","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"In a cumulative frequency graph, the lower quartile is 18years while the 60th percentile is 48 years. What percentage of the distribution is at most 18 years or greater than 48 years.","images":[],"options":{"A":"15%","B":"35%","C":"65%","D":"85%"},"answer":"C","explanation":"Percentage at most 18 years = 25% (i.e people between 1 - 18 years) percentage greater than 48 years = 40% i.e people older than 48 years which are above the 60th percentile.   \u2234 Percentage of the distribution at most 18 years or greater than 48years.    =25 + 40100x100%    =65100x100%    = 65%","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2014>43","subject":"Mathematics","year":"2014","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"If a number is selected at random from each of the sets P = {1,2,3} and Q = {2,3,5}, Find the probability that the sum of the numbers is prime.","images":[],"options":{"A":"5/9","B":"4/9","C":"1/3","D":"2/9"},"answer":"B","explanation":"Parameters given:  P = {1, 2, 3}  Q = {2, 3, 5}  The possible sums are stated in the table below   +235134624573568  From the table above, there are 9 possible sums which include 4 prime numbers.  P(primenumber)=49","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>44","subject":"Mathematics","year":"2014","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, O is the centre of the circle, PR is a tangent to the circle at Q and \u2220 SOQ = 86\u00b0.    Calculate the value of \u2220SQR.","images":["data:image/png;base64,"],"options":{"A":"43o","B":"47o","C":"54o","D":"86o"},"answer":"A","explanation":"N.B: \u2220OQR = 90\u00b0 (angle between a tangent and a radius)  \u2220OQR = \u2220OQS + \u2220SQR ---------------- (1)  In \u0394OQS  \u2220OQS + \u2220OSQ + \u2220SOQ = 180\u00b0 (sum of \u2220s in a \u0394)  N.B: \u2220OQS = \u2220OSQ {base angles of isosceles}  \u2220OQS + \u2220OQS + \u2220SOQ = 180\u00b0 (sum of \u2220s in a \u0394)  2OQS + SOQ = 180\u00b0  2OQS + 86 = 180\u00b0  2OQS = 94  \u2220OQS = 47\u00b0  From (1)  \u2220OQR = \u2220OQS + \u2220SQR  90 = 47 + \u2220SQR  \u2220SQR = 43\u00b0","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2014>45","subject":"Mathematics","year":"2014","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"If log5.957 = 0.7750, Find log&#179&radic;0.0005957&nbsp;","images":[],"options":{"A":"-4.1986","B":"-2.9250","C":"-1.5917","D":"-1.2853"},"answer":"B","explanation":"Therefore, log&#179&radic;0.0005957&nbsp; = -2.9250","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2014>46","subject":"Mathematics","year":"2014","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"The probability of an event P happening is 1/5 and that of event Q is 1/4. If the events are independents, what is the probability that neither of them happens?","images":[],"options":{"A":"4/5","B":"3/4","C":"3/5","D":"1/20"},"answer":"C","explanation":"Prob(P)=15    Prob(Q)=14    Prob(neither P) = 1 - 1/5   =5 - 15=45   Prob(neither Q) = 1 - 1/4 =4-14=34  Prob(neither of them) = 4/5 x 3/4 = 12/20 = 3/5","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>47","subject":"Mathematics","year":"2014","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"Each exterior angle of a polygon is 30o. Calculate the sum of the interior angles.","images":[],"options":{"A":"540o","B":"720o","C":"1080o","D":"1800o"},"answer":"D","explanation":"number of sides = 360o/\u03b8 = 360o/30o n = 12o   sum of interior angle = (n - 2)180o    = (12 - 2)180o = 10 x 180o = 1800o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>48","subject":"Mathematics","year":"2014","type":"Objective","topic":"NUMBER AND NUMERATION : SEQUENCE AND SERIES","question":"Find the number of terms in the Arithmetic Progression (A.P) 2, -9, -20, ..., -141.","images":[],"options":{"A":"11","B":"12","C":"13","D":"14"},"answer":"D","explanation":"T1 T2 T3    2, -9, -20, ........-141    l = a + (n - 1)d    first term, a = 2    common difference d = T3 - T2 = T2 - T1     -20 - (-9) = -9 -2     -20 + 9 = -11     -11 = -11;    d = -11    last term l = -141    -141 = 2 + (n - 1)(-11)   -141 = 2 + (-11n + 11)    = 2 - 11n + 11;    -141 = 13 - 11n    -141 - 13 = -11n;    -154 = -11n   n = -154/-11 = n = 14","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>49","subject":"Mathematics","year":"2014","type":"Objective","topic":"NUMBER AND NUMERATION : MODULAR ARITHMETIC","question":"In what modulus is it true that 9 + 8 = 5?","images":[],"options":{"A":"mod10","B":"mod 11","C":"mod 12","D":"mod 13"},"answer":"C","explanation":"9 + 8 = 17    17 \u00f7 mod 12 = 1 rem 5   Therefore, 9 + 8 = 5 is true in mod 12","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2014>50","subject":"Mathematics","year":"2014","type":"Objective","topic":"MENSURATION : VOLUMES","question":"The radii of the base of two cylindrical tins, P and Q are r and 2r respectively. If the water level in P is 10cm high, what would be the height of the same quantity of water in Q?","images":[],"options":{"A":"2.5cm","B":"5.0cm","C":"7.5cm","D":"20.0cm"},"answer":"A","explanation":"Volume of cylinder = \u03c0r2h    Volume of cylinder P = \u03c0r2 \u00d7 10    = 10\u03c0r2    Volume of cylinder Q = \u03c0r2h    = \u03c0(2r)2h    = 4\u03c0r2h    \u2234 4\u03c0r2h = 10\u03c0r2    4h = 10   h=104   = 2.5cm.","marks":"1","difficulty":"3"}];